 * @file sensor_types.h
 * @brief 传感器类型定义和数据结构
 * @author Embedded System Team
 * @date 2024-01-15
 * 
 * 定义温湿度监测系统中使用的传感器类型、数据结构和接口
 */

#ifndef SENSOR_TYPES_H
#define SENSOR_TYPES_H

#include <stdint.h>
#include <time.h>

#ifdef __cplusplus
extern "C" {
#endif

/**
 * @brief 传感器类型枚举
 */
typedef enum {
    SENSOR_TYPE_DHT11 = 0,      /**< DHT11温湿度传感器 */
    SENSOR_TYPE_DHT22,          /**< DHT22/AM2302温湿度传感器 */
    SENSOR_TYPE_BMP280,         /**< BMP280气压温度传感器 */
    SENSOR_TYPE_BH1750,         /**< BH1750光照传感器 */
    SENSOR_TYPE_DS18B20,        /**< DS18B20温度传感器 */
    SENSOR_TYPE_MAX             /**< 传感器类型数量 */
} sensor_type_t;

/**
 * @brief 传感器状态枚举
 */
typedef enum {
    SENSOR_STATUS_OK = 0,       /**< 传感器正常 */
    SENSOR_STATUS_ERROR,        /**< 传感器错误 */
    SENSOR_STATUS_TIMEOUT,      /**< 传感器超时 */
    SENSOR_STATUS_CHECKSUM_ERROR, /**< 校验和错误 */
    SENSOR_STATUS_NOT_CONNECTED, /**< 传感器未连接 */
    SENSOR_STATUS_INIT_FAILED   /**< 初始化失败 */
} sensor_status_t;

/**
 * @brief 传感器配置结构体
 */
typedef struct {
    sensor_type_t type;         /**< 传感器类型 */
    uint8_t gpio_pin;           /**< GPIO引脚号（GPIO传感器使用） */
    uint8_t i2c_address;        /**< I2C地址（I2C传感器使用） */
    uint8_t i2c_bus;            /**< I2C总线号 */
    uint32_t sample_interval;   /**< 采样间隔（毫秒） */
    char name[32];              /**< 传感器名称 */
    void *private_data;         /**< 私有数据指针 */
} sensor_config_t;

/**
 * @brief 传感器数据结构体
 */
typedef struct {
    time_t timestamp;           /**< 时间戳 */
    float temperature;          /**< 温度（摄氏度） */
    float humidity;             /**< 湿度（百分比） */
    float pressure;             /**< 气压（hPa，可选） */
    float light;                /**< 光照强度（lux，可选） */
    sensor_type_t sensor_type;  /**< 传感器类型 */
    sensor_status_t status;     /**< 传感器状态 */
    uint8_t sensor_id;          /**< 传感器ID */
} sensor_data_t;

/**
 * @brief 传感器操作接口结构体
 */
typedef struct {
    /** 初始化传感器 */
    sensor_status_t (*init)(sensor_config_t *config);

    /** 读取传感器数据 */
    sensor_status_t (*read)(sensor_data_t *data);

    /** 释放传感器资源 */
    void (*cleanup)(void);

    /** 获取传感器信息 */
    const char* (*get_info)(void);

    /** 传感器校准（可选） */
    sensor_status_t (*calibrate)(float *params, int param_count);
} sensor_ops_t;

/**
 * @brief 传感器实例结构体
 */
typedef struct {
    sensor_config_t config;     /**< 传感器配置 */
    sensor_ops_t ops;           /**< 传感器操作接口 */
    sensor_data_t last_data;    /**< 最后一次读取的数据 */
    uint32_t read_count;        /**< 读取次数 */
    uint32_t error_count;       /**< 错误次数 */
    uint8_t is_initialized;     /**< 初始化标志 */
} sensor_instance_t;

/**
 * @brief 报警阈值结构体
 */
typedef struct {
    float temp_high;            /**< 温度高阈值 */
    float temp_low;             /**< 温度低阈值 */
    float humidity_high;        /**< 湿度高阈值 */
    float humidity_low;         /**< 湿度低阈值 */
    uint8_t enabled;            /**< 报警使能标志 */
} alarm_threshold_t;

/**
 * @brief 系统配置结构体
 */
typedef struct {
    uint8_t sensor_count;               /**< 传感器数量 */
    sensor_instance_t *sensors;         /**< 传感器实例数组 */
    alarm_threshold_t alarm_threshold;  /**< 报警阈值 */
    uint32_t log_interval;              /**< 日志记录间隔（秒） */
    char log_file[256];                 /**< 日志文件路径 */
    uint8_t daemon_mode;                /**< 守护进程模式标志 */
    uint8_t verbose;                    /**< 详细输出标志 */
} system_config_t;

// 常量定义
#define MAX_SENSORS 8                    /**< 最大传感器数量 */
#define DEFAULT_SAMPLE_INTERVAL 2000     /**< 默认采样间隔（毫秒） */
#define DEFAULT_LOG_INTERVAL 3600        /**< 默认日志间隔（秒） */

// 温度单位转换
#define CELSIUS_TO_FAHRENHEIT(c) ((c) * 9.0 / 5.0 + 32.0)
#define FAHRENHEIT_TO_CELSIUS(f) (((f) - 32.0) * 5.0 / 9.0)

// 错误码定义
#define SENSOR_SUCCESS 0
#define SENSOR_ERROR_INIT -1
#define SENSOR_ERROR_READ -2
#define SENSOR_ERROR_PARAM -3
#define SENSOR_ERROR_MEMORY -4
#define SENSOR_ERROR_IO -5

// 函数声明

/**
 * @brief 创建传感器实例
 * 
 * @param type 传感器类型
 * @param config 传感器配置
 * @return sensor_instance_t* 传感器实例指针，失败返回NULL
 */
sensor_instance_t* sensor_create(sensor_type_t type, sensor_config_t *config);

/**
 * @brief 销毁传感器实例
 * 
 * @param sensor 传感器实例指针
 */
void sensor_destroy(sensor_instance_t *sensor);

/**
 * @brief 读取传感器数据
 * 
 * @param sensor 传感器实例
 * @param data 输出数据指针
 * @return sensor_status_t 读取状态
 */
sensor_status_t sensor_read_data(sensor_instance_t *sensor, sensor_data_t *data);

/**
 * @brief 获取传感器状态字符串
 * 
 * @param status 传感器状态
 * @return const char* 状态字符串
 */
const char* sensor_status_to_string(sensor_status_t status);

/**
 * @brief 获取传感器类型字符串
 * 
 * @param type 传感器类型
 * @return const char* 类型字符串
 */
const char* sensor_type_to_string(sensor_type_t type);

/**
 * @brief 检查是否需要报警
 * 
 * @param data 传感器数据
 * @param threshold 报警阈值
 * @return int 报警标志位（bit0:温度高, bit1:温度低, bit2:湿度高, bit3:湿度低）
 */
int check_alarm(const sensor_data_t *data, const alarm_threshold_t *threshold);

/**
 * @brief 格式化传感器数据为JSON字符串
 * 
 * @param data 传感器数据
 * @param buffer 输出缓冲区
 * @param size 缓冲区大小
 * @return int 写入的字符数，失败返回-1
 */
int format_sensor_data_json(const sensor_data_t *data, char *buffer, size_t size);

/**
 * @brief 格式化传感器数据为CSV字符串
 * 
 * @param data 传感器数据
 * @param buffer 输出缓冲区
 * @param size 缓冲区大小
 * @return int 写入的字符数，失败返回-1
 */
int format_sensor_data_csv(const sensor_data_t *data, char *buffer, size_t size);

#ifdef __cplusplus
}
#endif

#endif /* SENSOR_TYPES_H */"}

{"path": "C:\Users\14355\Desktop\嵌综\emb-agent\workspace\projects\temperature_humidity_monitor\include\i2c_sensors.h", "content": "/**
 * @file i2c_sensors.h
 * @brief I2C传感器通用接口
 * @author Embedded System Team
 * @date 2024-01-15
 * 
 * 支持多种I2C接口的传感器，包括BMP280、BH1750等
 */

#ifndef I2C_SENSORS_H
#define I2C_SENSORS_H

#include "sensor_types.h"

#ifdef __cplusplus
extern "C" {
#endif

// I2C传感器类型
typedef enum {
    I2C_SENSOR_BMP280 = 0,      /**< BMP280气压温度传感器 */
    I2C_SENSOR_BH1750,          /**< BH1750光照传感器 */
    I2C_SENSOR_SHT30,           /**< SHT30温湿度传感器 */
    I2C_SENSOR_MAX
} i2c_sensor_type_t;

// I2C配置结构体
typedef struct {
    uint8_t bus_number;         /**< I2C总线号 */
    uint8_t device_address;     /**< 设备地址 */
    uint32_t timeout_ms;        /**< 超时时间（毫秒） */
    uint32_t clock_speed;       /**< I2C时钟速度（Hz） */
} i2c_config_t;

// I2C传感器配置
typedef struct {
    i2c_sensor_type_t type;     /**< I2C传感器类型 */
    i2c_config_t i2c_config;    /**< I2C配置 */
    void *sensor_config;        /**< 传感器特定配置 */
} i2c_sensor_config_t;

// I2C传感器操作接口
typedef struct {
    /** 初始化I2C传感器 */
    sensor_status_t (*init)(i2c_sensor_config_t *config);

    /** 读取I2C传感器数据 */
    sensor_status_t (*read)(sensor_data_t *data);

    /** 释放I2C传感器资源 */
    void (*cleanup)(void);

    /** 获取I2C传感器信息 */
    const char* (*get_info)(void);

    /** I2C传感器校准 */
    sensor_status_t (*calibrate)(float *params, int param_count);
} i2c_sensor_ops_t;

/**
 * @brief 初始化I2C总线
 * 
 * @param bus_number I2C总线号
 * @param clock_speed 时钟速度（Hz）
 * @return int 成功返回文件描述符，失败返回-1
 */
int i2c_init_bus(uint8_t bus_number, uint32_t clock_speed);

/**
 * @brief 关闭I2C总线
 * 
 * @param fd I2C文件描述符
 */
void i2c_close_bus(int fd);

/**
 * @brief I2C写一个字节
 * 
 * @param fd I2C文件描述符
 * @param addr 设备地址
 * @param reg 寄存器地址
 * @param value 要写入的值
 * @return int 成功返回0，失败返回-1
 */
int i2c_write_byte(int fd, uint8_t addr, uint8_t reg, uint8_t value);

/**
 * @brief I2C读一个字节
 * 
 * @param fd I2C文件描述符
 * @param addr 设备地址
 * @param reg 寄存器地址
 * @param value 输出值指针
 * @return int 成功返回0，失败返回-1
 */
int i2c_read_byte(int fd, uint8_t addr, uint8_t reg, uint8_t *value);

/**
 * @brief I2C读多个字节
 * 
 * @param fd I2C文件描述符
 * @param addr 设备地址
 * @param reg 起始寄存器地址
 * @param buffer 输出缓冲区
 * @param length 要读取的字节数
 * @return int 成功返回0，失败返回-1
 */
int i2c_read_bytes(int fd, uint8_t addr, uint8_t reg, uint8_t *buffer, uint8_t length);

/**
 * @brief I2C写多个字节
 * 
 * @param fd I2C文件描述符
 * @param addr 设备地址
 * @param reg 起始寄存器地址
 * @param buffer 数据缓冲区
 * @param length 要写入的字节数
 * @return int 成功返回0，失败返回-1
 */
int i2c_write_bytes(int fd, uint8_t addr, uint8_t reg, uint8_t *buffer, uint8_t length);

/**
 * @brief I2C读16位数据
 * 
 * @param fd I2C文件描述符
 * @param addr 设备地址
 * @param reg 寄存器地址
 * @param value 输出值指针
 * @return int 成功返回0，失败返回-1
 */
int i2c_read_word(int fd, uint8_t addr, uint8_t reg, uint16_t *value);

/**
 * @brief I2C写16位数据
 * 
 * @param fd I2C文件描述符
 * @param addr 设备地址
 * @param reg 寄存器地址
 * @param value 要写入的值
 * @return int 成功返回0，失败返回-1
 */
int i2c_write_word(int fd, uint8_t addr, uint8_t reg, uint16_t value);

// BMP280传感器相关
#define BMP280_DEFAULT_ADDRESS 0x76     /**< BMP280默认I2C地址 */
#define BMP280_ALT_ADDRESS 0x77         /**< BMP280备用I2C地址 */

// BMP280寄存器定义
#define BMP280_REG_ID 0xD0
#define BMP280_REG_RESET 0xE0
#define BMP280_REG_STATUS 0xF3
#define BMP280_REG_CTRL_MEAS 0xF4
#define BMP280_REG_CONFIG 0xF5
#define BMP280_REG_PRESS_MSB 0xF7
#define BMP280_REG_TEMP_MSB 0xFA

// BMP280校准寄存器
#define BMP280_REG_CALIB00 0x88
#define BMP280_REG_CALIB25 0xA1

// BMP280操作模式
typedef enum {
    BMP280_MODE_SLEEP = 0,
    BMP280_MODE_FORCED = 1,
    BMP280_MODE_NORMAL = 3
} bmp280_mode_t;

// BMP280过采样设置
typedef enum {
    BMP280_OSRS_SKIP = 0,
    BMP280_OSRS_1 = 1,
    BMP280_OSRS_2 = 2,
    BMP280_OSRS_4 = 3,
    BMP280_OSRS_8 = 4,
    BMP280_OSRS_16 = 5
} bmp280_oversampling_t;

// BMP280滤波器设置
typedef enum {
    BMP280_FILTER_OFF = 0,
    BMP280_FILTER_2 = 1,
    BMP280_FILTER_4 = 2,
    BMP280_FILTER_8 = 3,
    BMP280_FILTER_16 = 4
} bmp280_filter_t;

// BMP280配置结构体
typedef struct {
    bmp280_mode_t mode;                 /**< 操作模式 */
    bmp280_oversampling_t temp_osrs;    /**< 温度过采样 */
    bmp280_oversampling_t press_osrs;   /**< 气压过采样 */
    bmp280_filter_t filter;             /**< 滤波器设置 */
    uint8_t standby_time;               /**< 待机时间 */
} bmp280_config_t;

// BMP280校准数据
typedef struct {
    uint16_t dig_T1;
    int16_t dig_T2;
    int16_t dig_T3;
    uint16_t dig_P1;
    int16_t dig_P2;
    int16_t dig_P3;
